const event = $('Execute Workflow Trigger').item.json || {};
const analysis = $('Fetch Last Analysis').first()?.json || {};
const overdue = $json || {};

return [{
  json: {
    correlation_id: event.correlation_id || `release-guard-${Date.now()}`,
    repo: event.repo || 'unknown',
    branch: event.branch || 'main',
    actor: event.actor || 'system',
    hay_problemas: analysis.hay_problemas || false,
    severidad_maxima: analysis.severidad_maxima || 'none',
    tareas_vencidas: Number(analysis.tareas_vencidas || 0),
    progreso_pct: Number(analysis.progreso_pct || 0),
    prs_abiertos_backend: Number(analysis.prs_abiertos_backend || 0),
    prs_abiertos_frontend: Number(analysis.prs_abiertos_frontend || 0),
    tareas_criticas_proximas: Number(overdue.tareas_criticas || 0),
    recomendaciones_previas: analysis.recomendaciones_ia || 'ninguna'
  }
}];

const raw = $json.text || $json.output || $json.response || JSON.stringify($json || {});
let cleaned = String(raw).trim();

cleaned = cleaned
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

const start = cleaned.indexOf('{');
const end = cleaned.lastIndexOf('}');
if (start !== -1 && end !== -1 && end > start) {
  cleaned = cleaned.slice(start, end + 1);
}

let decision;
try {
  decision = JSON.parse(cleaned);
} catch (error) {
  decision = {
    release_approved: false,
    confidence: 0.5,
    risk_level: 'high',
    blockers: ['No se pudo parsear la respuesta del modelo como JSON valido.'],
    warnings: [String(raw).slice(0, 500)],
    recommendation: 'Revisar manualmente el release porque la decision automatica no pudo interpretarse.',
    requires_human_approval: true
  };
}

decision.release_approved = Boolean(decision.release_approved);
decision.confidence = Number(decision.confidence || 0.5);
decision.risk_level = ['low', 'medium', 'high', 'critical'].includes(decision.risk_level) ? decision.risk_level : 'high';
decision.blockers = Array.isArray(decision.blockers) ? decision.blockers : [];
decision.warnings = Array.isArray(decision.warnings) ? decision.warnings : [];
decision.recommendation = decision.recommendation || 'Revisar manualmente antes de liberar.';
decision.requires_human_approval = Boolean(decision.requires_human_approval);

return [{ json: decision }];

const decision = $json || {};
const ctx = $('Merge Release Context').item.json || {};

const emoji = decision.release_approved ? '✅' : '🚫';
const status = decision.release_approved ? 'APROBADO' : 'BLOQUEADO';
const riskEmoji = { low: '🟢', medium: '🟡', high: '🟠', critical: '🔴' }[decision.risk_level] || '⚪';

const lines = [
  `${emoji} **Release Guard — ${status}** ${riskEmoji}`,
  '',
  `📦 **Release:** \`${ctx.branch}\` en \`${ctx.repo}\``,
  `👤 **Solicitado por:** ${ctx.actor}`,
  `📊 **Confianza:** ${Math.round((decision.confidence || 0) * 100)}%`,
  ''
];

const blockers = Array.isArray(decision.blockers) ? decision.blockers : [];
const warnings = Array.isArray(decision.warnings) ? decision.warnings : [];

if (blockers.length > 0) {
  lines.push('🚫 **Bloqueos:**');
  blockers.forEach(b => lines.push(`  - ${b}`));
  lines.push('');
}

if (warnings.length > 0) {
  lines.push('⚠️ **Advertencias:**');
  warnings.forEach(w => lines.push(`  - ${w}`));
  lines.push('');
}

lines.push(`💬 **Recomendación:** ${decision.recommendation || 'Revisar manualmente antes de liberar.'}`);

if (decision.requires_human_approval) {
  lines.push('', '🔑 *Requiere aprobación del Tech Lead.*');
}

return [{
  json: {
    content: lines.join('\n').slice(0, 2000),
    release_approved: decision.release_approved,
    risk_level: decision.risk_level,
    confidence: decision.confidence,
    blockers,
    warnings,
    recommendation: decision.recommendation,
    requires_human_approval: decision.requires_human_approval,
    correlation_id: ctx.correlation_id,
    event_id: 'release-guard:' + ctx.correlation_id,
    idempotency_key: 'release-guard:' + ctx.correlation_id
  }
}];

const d = $('Build Release Message').item.json || {};
const ctx = $('Merge Release Context').item.json || {};

return [{
  json: {
    correlation_id: d.correlation_id,
    agent_role: 'Release Guard',
    decision_type: 'release_gate',
    input_summary: `Release gate for ${ctx.branch || 'main'} in ${ctx.repo || 'unknown'}`,
    context_used: {
      repo: ctx.repo,
      branch: ctx.branch,
      actor: ctx.actor,
      hay_problemas: ctx.hay_problemas,
      severidad_maxima: ctx.severidad_maxima,
      tareas_vencidas: ctx.tareas_vencidas,
      progreso_pct: ctx.progreso_pct,
      prs_abiertos_backend: ctx.prs_abiertos_backend,
      prs_abiertos_frontend: ctx.prs_abiertos_frontend,
      tareas_criticas_proximas: ctx.tareas_criticas_proximas,
      recomendaciones_previas: ctx.recomendaciones_previas
    },
    evidence: {},
    decision: {
      release_approved: d.release_approved,
      blockers: d.blockers || [],
      warnings: d.warnings || []
    },
    recommendation: d.recommendation,
    confidence: d.confidence || 0.9,
    risk_level: d.risk_level || 'high',
    requires_human_approval: d.requires_human_approval
  }
}];
